= createInitialState(\\\"status-cap\\\");\\n    const statuses: StatusId[] = [\\\"poison\\\", \\\"burn\\\", \\\"regen\\\", \\\"stun\\\"];\\n\\n    for (const status of statuses) {\\n      state = applyStatus(\\n        state,\\n        \\\"player\\\",\\n        status,\\n        bounds.statusVocabulary.durationTurns[status].min,\\n      ).state;\\n    }\\n\\n    const capped = applyStatus(\\n      state,\\n      \\\"player\\\",\\n      \\\"blind\\\",\\n      bounds.statusVocabulary.durationTurns.blind.min,\\n    );\\n\\n    expect(capped.state.player.statuses.map((entry) => entry.status)).toEqual([\\n      \\\"burn\\\",\\n      \\\"regen\\\",\\n      \\\"stun\\\",\\n      \\\"blind\\\",\\n    ]);\\n    expect(capped.events).toContainEqual({\\n      turn: 0,\\n      type: \\\"status_dropped_oldest\\\",\\n      data: {\\n        entityId: \\\"player\\\",\\n        status: \\\"poison\\\",\\n      },\\n    });\\n  });\\n\\n  it(\\\"rejects out-of-bounds durations\\\", () => {\\n    const state = createInitialState(\\\"status-bounds\\\");\\n    const result = applyStatus(state, \\\"player\\\", \\\"poison\\\", 1);\\n\\n    expect(result.state).toBe(state);\\n    expect(result.events).toEqual([]);\\n  });\\n});\\n\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n./phase-plans/PHASE-13B-EFFECTS-SPATIAL.md:7:GAME_DESIGN §7 (verb rows: summon from floor roster only, transform ≤ equal budget cost, dig 1–5 line); 07A map utilities.\n./phase-plans/PHASE-13B-EFFECTS-SPATIAL.md:36:4. Acceptance bar: every targeting shape in GAME_DESIGN §7 is computable from geometry.ts alone.\n./phase-plans/PHASE-26-FALLBACK-CONTENT.md:7:NORTH_STAR §4.5 (offline invariant); WORLD §4.3 (Old Stock: unpersonalized on purpose); GAME_DESIGN §8–10 (bounds it must satisfy); 21's content-injection interface.\n./runs/sessions/phase13b-spatial.jsonl:5:{\"type\":\"item.started\",\"item\":{\"id\":\"item_2\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,220p' /Users/keigoshimada/.code